<template>
  <CCard class="mb-4">
    <CCardBody class="p-0">
      <CDataTable class="custom-table mb-0" :items="items" :fields="fields" :items-per-page="5" hover>
        <template #nameContent="{ item }">
          <td class="align-middle px-4 py-3">
            <div class="d-flex align-items-center">
              <div class="mr-3 doc-icon-wrapper" :class="getIconClass(item.type)">
                <CIcon :name="getIconName(item.type)" class="doc-icon-svg" />
              </div>
              <div>
                <div class="font-weight-bold" style="color: #1f2937; font-size: 14px;">{{ item.name }}</div>
                <div class="text-muted small">{{ item.type }} &bull; {{ item.downloads }} downloads</div>
              </div>
            </div>
          </td>
        </template>

        <template #status="{ item }">
          <td class="align-middle">
            <CBadge :color="item.status === 'Active' ? 'success' : 'secondary'" class="custom-badge">
              {{ item.status }}
            </CBadge>
          </td>
        </template>

        <template #actions="{ item }">
          <td class="align-middle text-right px-4 py-3">
            <CButton class="btn-action-icon mr-1" title="Download" @click="$emit('download', item)">
              <CIcon name="cil-data-transfer-down" />
            </CButton>
            <CButton class="btn-action-icon" title="Options" @click="$emit('options', item)">
              <CIcon name="cil-options" />
            </CButton>
          </td>
        </template>
      </CDataTable>
    </CCardBody>
  </CCard>
</template>

<script>
export default {
  name: 'DocumentsTable',
  props: {
    items: { type: Array, default: () => [] },
    fields: { type: Array, default: () => [] }
  },
  methods: {
    getIconClass(type) {
      if (type === 'PDF') return 'doc-icon-pdf'
      if (type === 'Word') return 'doc-icon-word'
      if (type === 'Excel') return 'doc-icon-excel'
      return 'doc-icon-default'
    },
    getIconName(type) {
      if (type === 'PDF') return 'cil-file'
      if (type === 'Word') return 'cil-description'
      if (type === 'Excel') return 'cil-spreadsheet'
      return 'cil-file'
    }
  }
}
</script>

<style scoped>
.custom-badge {
  background-color: #f3f4f6;
  color: #4b5563;
  font-weight: 600;
  padding: 6px 12px;
  border-radius: 12px;
  font-size: 11px;
}

.doc-icon-wrapper {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  border-radius: 8px;
}

.doc-icon-svg {
  width: 18px;
  height: 18px;
}

.doc-icon-pdf {
  background-color: #fef2f2;
  color: #dc2626;
}

.doc-icon-word {
  background-color: #eff6ff;
  color: #2563eb;
}

.doc-icon-excel {
  background-color: #f0fdf4;
  color: #16a34a;
}

.doc-icon-default {
  background-color: #f3f4f6;
  color: #6b7280;
}

.btn-action-icon {
  background-color: transparent !important;
  border: none !important;
  color: #9ca3af !important;
  border-radius: 6px;
  padding: 6px 8px;
  transition: all 0.2s;
  box-shadow: none !important;
}

.btn-action-icon:hover {
  color: #4b5563 !important;
  background-color: #f3f4f6 !important;
}

.btn-action-icon:focus {
  box-shadow: none !important;
}
</style>
